import type { BlobNode, Shape } from '../types';
import { clamp, generateBlobNodes, shapeToPath } from './geometry';

export type FluidBody = {
  id: string;
  x: number;
  y: number;
  vx: number;
  vy: number;
  width: number;
  height: number;
  rotation: number;
  /** Residual liquid energy 0…1+ */
  jiggle: number;
  settle: number;
  locked: boolean;
  fingerTarget: { x: number; y: number } | null;
  grabOffset: { x: number; y: number };
  /** Approximate ink volume (px²) for conservation on merge */
  mass: number;
  /** Wetness: higher = more fluid, slower to settle */
  wetness: number;
};

export type FluidSample = {
  x: number;
  y: number;
  t: number;
};

const FRICTION = 0.968;
const MIN_VEL = 0.04;
const EDGE_BOUNCE = 0.38;
const MAX_SPEED = 64;
const JIGGLE_DECAY = 0.952;
const FINGER_SPRING = 0.4;
const FINGER_DAMP = 0.76;
const SURFACE_TENSION = 0.028;
const MAX_PUDDLE = 640;
/** Overlap fraction that triggers coalesce (lower = easier merge) */
const MERGE_OVERLAP = 0.28;

export function createBodyFromShape(shape: Shape): FluidBody {
  const mass = Math.max(400, shape.width * shape.height);
  return {
    id: shape.id,
    x: shape.x,
    y: shape.y,
    vx: 0,
    vy: 0,
    width: shape.width,
    height: shape.height,
    rotation: shape.rotation,
    jiggle: 0,
    settle: 0,
    locked: shape.locked,
    fingerTarget: null,
    grabOffset: { x: 0, y: 0 },
    mass,
    wetness: 0.9,
  };
}

export function velocityFromSamples(samples: FluidSample[]): { vx: number; vy: number } {
  if (samples.length < 2) return { vx: 0, vy: 0 };
  const recent = samples.slice(-8);
  const a = recent[0];
  const b = recent[recent.length - 1];
  const dt = Math.max(0.008, (b.t - a.t) / 1000);
  let vx = ((b.x - a.x) / dt) * 0.016;
  let vy = ((b.y - a.y) / dt) * 0.016;
  const speed = Math.hypot(vx, vy);
  if (speed > MAX_SPEED) {
    const s = MAX_SPEED / speed;
    vx *= s;
    vy *= s;
  }
  return { vx, vy };
}

/**
 * Highly fluid organic deformation — stretched filaments, surface ripples.
 */
export function liquidDeformNodes(
  nodes: BlobNode[],
  vx: number,
  vy: number,
  jiggle: number,
  time: number,
  softness = 0.55,
  wetness = 0.8,
): BlobNode[] {
  const speed = Math.hypot(vx, vy);
  const angle = speed > 0.01 ? Math.atan2(vy, vx) : 0;
  const stretchAmt = clamp(speed * 0.028 * (0.55 + wetness), 0, 0.85);
  const jAmt = clamp(jiggle * (0.75 + wetness * 0.55), 0, 2);

  return nodes.map((n, i) => {
    const align = Math.cos(n.angle - angle);
    // Leading edge pushes out, trailing edge pulls in (liquid blob)
    const stretch =
      1 +
      align * stretchAmt * 1.35 -
      (1 - Math.abs(align)) * stretchAmt * 0.55 +
      Math.sin(n.angle * 3 + time * 4) * stretchAmt * 0.1;
    const ripple =
      Math.sin(time * 10 + i * 1.15 + n.angle * 2.4) * jAmt * 0.13 +
      Math.sin(time * 16 + i * 0.55) * jAmt * 0.06 +
      Math.cos(time * 6 + n.angle * 5) * jAmt * wetness * 0.05;
    const capillary = Math.sin(time * 2.4 + n.angle * 7) * wetness * 0.04;
    const radius = clamp(n.radius * stretch + ripple + capillary, 0.18, 1.7);
    const tension = clamp(
      n.tension + softness * 0.18 + stretchAmt * 0.4 + jAmt * 0.2 + wetness * 0.1,
      0.16,
      0.99,
    );
    return { ...n, radius, tension };
  });
}

export function shapePathWithFluid(
  shape: Shape,
  body: FluidBody | undefined,
  time: number,
  morphPhase: number,
  morphAmp: number,
  softness: number,
): string {
  const vx = body?.vx ?? 0;
  const vy = body?.vy ?? 0;
  const jiggle = (body?.jiggle ?? 0) + morphAmp * 0.3;
  const wetness = body?.wetness ?? 0.75;
  const nodes =
    Math.hypot(vx, vy) > 0.02 || jiggle > 0.012 || wetness > 0.45
      ? liquidDeformNodes(shape.nodes, vx, vy, jiggle, time, softness, wetness)
      : shape.nodes;
  const local: Shape = {
    ...shape,
    x: 0,
    y: 0,
    width: body?.width ?? shape.width,
    height: body?.height ?? shape.height,
    nodes,
  };
  return shapeToPath(local, morphPhase, morphAmp);
}

export function integrateBody(
  body: FluidBody,
  canvasW: number,
  canvasH: number,
  dt = 1,
): boolean {
  if (body.locked) {
    body.vx = 0;
    body.vy = 0;
    body.jiggle *= JIGGLE_DECAY;
    body.fingerTarget = null;
    return body.jiggle > 0.02;
  }

  // Viscous follow under brush / finger
  if (body.fingerTarget) {
    const cx = body.x + body.width / 2;
    const cy = body.y + body.height / 2;
    const tx = body.fingerTarget.x - body.grabOffset.x;
    const ty = body.fingerTarget.y - body.grabOffset.y;
    const spring = FINGER_SPRING * (0.75 + body.wetness * 0.45);
    body.vx += (tx - cx) * spring * dt;
    body.vy += (ty - cy) * spring * dt;
    body.vx *= FINGER_DAMP;
    body.vy *= FINGER_DAMP;
    body.jiggle = Math.max(body.jiggle, 0.6 + Math.hypot(body.vx, body.vy) * 0.045);
    body.wetness = Math.min(1.35, body.wetness + 0.012 * dt);
  }

  body.x += body.vx * dt;
  body.y += body.vy * dt;

  if (!body.fingerTarget) {
    // Wet ink slides further; drying increases friction
    const fric = FRICTION - body.wetness * 0.014;
    body.vx *= clamp(fric, 0.88, 0.99);
    body.vy *= clamp(fric, 0.88, 0.99);
    body.wetness = Math.max(0.22, body.wetness - 0.0032 * dt);
  }

  // Surface tension: puddle slowly wants to be round
  if (!body.fingerTarget && body.wetness > 0.28) {
    const avg = (body.width + body.height) / 2;
    const k = SURFACE_TENSION * body.wetness * dt;
    body.width += (avg - body.width) * k;
    body.height += (avg - body.height) * k;
  }

  // Gentle mass-conserving settle toward area ≈ mass
  const area = Math.max(1, body.width * body.height);
  if (Math.abs(area - body.mass) > body.mass * 0.06) {
    const s = Math.sqrt(body.mass / area);
    const k = 0.05 * dt;
    body.width *= 1 + (s - 1) * k;
    body.height *= 1 + (s - 1) * k;
  }

  body.jiggle *= JIGGLE_DECAY + body.wetness * 0.012;
  if (body.settle > 0) body.settle -= 0.014 * dt;

  const pad = 2;
  if (body.x < pad) {
    body.x = pad;
    body.vx = Math.abs(body.vx) * EDGE_BOUNCE;
    body.jiggle = Math.min(1.6, body.jiggle + 0.45);
  }
  if (body.y < pad) {
    body.y = pad;
    body.vy = Math.abs(body.vy) * EDGE_BOUNCE;
    body.jiggle = Math.min(1.6, body.jiggle + 0.45);
  }
  if (body.x + body.width > canvasW - pad) {
    body.x = canvasW - pad - body.width;
    body.vx = -Math.abs(body.vx) * EDGE_BOUNCE;
    body.jiggle = Math.min(1.6, body.jiggle + 0.45);
  }
  if (body.y + body.height > canvasH - pad) {
    body.y = canvasH - pad - body.height;
    body.vy = -Math.abs(body.vy) * EDGE_BOUNCE;
    body.jiggle = Math.min(1.6, body.jiggle + 0.45);
  }

  body.width = clamp(body.width, 14, MAX_PUDDLE);
  body.height = clamp(body.height, 14, MAX_PUDDLE);

  if (Math.hypot(body.vx, body.vy) > 0.3) {
    body.rotation += body.vx * 0.032 * dt * body.wetness;
  }

  if (Math.hypot(body.vx, body.vy) < MIN_VEL && !body.fingerTarget) {
    body.vx = 0;
    body.vy = 0;
  }

  return (
    Math.hypot(body.vx, body.vy) > 0 ||
    body.jiggle > 0.02 ||
    body.settle > 0 ||
    body.fingerTarget != null ||
    body.wetness > 0.5
  );
}

/**
 * Soft collision + coalesce when puddles heavily overlap.
 * Returns id of body absorbed (to remove), or null.
 */
export function softCollideOrMerge(
  a: FluidBody,
  b: FluidBody,
): { absorbedId: string | null } {
  if (a.locked && b.locked) return { absorbedId: null };
  const ax = a.x + a.width / 2;
  const ay = a.y + a.height / 2;
  const bx = b.x + b.width / 2;
  const by = b.y + b.height / 2;
  const dx = bx - ax;
  const dy = by - ay;
  const dist = Math.hypot(dx, dy) || 0.001;
  const ra = (a.width + a.height) * 0.3;
  const rb = (b.width + b.height) * 0.3;
  const minDist = ra + rb;

  if (dist >= minDist * 1.08) return { absorbedId: null };

  const overlap = (minDist - dist) / minDist;

  // Strong overlap + both wet → one liquid mass
  const eitherGrabbed = a.fingerTarget != null || b.fingerTarget != null;
  if (
    overlap > MERGE_OVERLAP &&
    a.wetness > 0.28 &&
    b.wetness > 0.28 &&
    !a.locked &&
    !b.locked &&
    // Allow merge while pouring if the active brush holds one of them
    (!eitherGrabbed || a.fingerTarget != null || b.fingerTarget != null)
  ) {
    // Prefer keeping the finger-held / larger mass
    let keep = a.mass >= b.mass ? a : b;
    let eat = keep === a ? b : a;
    if (a.fingerTarget && !b.fingerTarget) {
      keep = a;
      eat = b;
    } else if (b.fingerTarget && !a.fingerTarget) {
      keep = b;
      eat = a;
    }

    const totalMass = keep.mass + eat.mass;
    const kcx = (ax * a.mass + bx * b.mass) / totalMass;
    const kcy = (ay * a.mass + by * b.mass) / totalMass;
    const side = Math.sqrt(totalMass);
    keep.mass = totalMass;
    keep.width = clamp(side * (0.92 + Math.random() * 0.16), 28, MAX_PUDDLE);
    keep.height = clamp(side * (0.86 + Math.random() * 0.18), 28, MAX_PUDDLE);
    keep.x = kcx - keep.width / 2;
    keep.y = kcy - keep.height / 2;
    keep.vx = (a.vx * a.mass + b.vx * b.mass) / totalMass;
    keep.vy = (a.vy * a.mass + b.vy * b.mass) / totalMass;
    keep.jiggle = Math.min(1.8, Math.max(a.jiggle, b.jiggle) + 0.55);
    keep.wetness = Math.min(1.35, (a.wetness * a.mass + b.wetness * b.mass) / totalMass + 0.08);
    keep.settle = 0.85;
    if (eat.fingerTarget && !keep.fingerTarget) {
      keep.fingerTarget = eat.fingerTarget;
      keep.grabOffset = eat.grabOffset;
    }
    return { absorbedId: eat.id };
  }

  // Soft push (surface tension repulsion)
  const nx = dx / dist;
  const ny = dy / dist;
  const push = overlap * 1.15 * (0.55 + (a.wetness + b.wetness) * 0.22);
  const j = overlap * 0.2;

  if (!a.locked && !a.fingerTarget) {
    a.vx -= nx * push;
    a.vy -= ny * push;
    a.jiggle = Math.min(1.5, a.jiggle + j);
  }
  if (!b.locked && !b.fingerTarget) {
    b.vx += nx * push;
    b.vy += ny * push;
    b.jiggle = Math.min(1.5, b.jiggle + j);
  }
  return { absorbedId: null };
}

/** @deprecated use softCollideOrMerge */
export function softCollide(a: FluidBody, b: FluidBody): void {
  softCollideOrMerge(a, b);
}

export function applyProximityField(
  body: FluidBody,
  px: number,
  py: number,
  strength = 1,
): void {
  if (body.locked || body.fingerTarget) return;
  const cx = body.x + body.width / 2;
  const cy = body.y + body.height / 2;
  const dx = cx - px;
  const dy = cy - py;
  const dist = Math.hypot(dx, dy) || 0.001;
  const radius = Math.max(body.width, body.height) * 0.95 + 80;
  if (dist > radius) return;

  const falloff = 1 - dist / radius;
  const force = falloff * falloff * 0.48 * strength * body.wetness;
  body.vx += (dx / dist) * force;
  body.vy += (dy / dist) * force;
  body.jiggle = Math.min(1.35, body.jiggle + falloff * 0.12);
}

export function applyTrackpadPush(
  body: FluidBody,
  dx: number,
  dy: number,
  px: number,
  py: number,
): void {
  if (body.locked) return;
  const cx = body.x + body.width / 2;
  const cy = body.y + body.height / 2;
  const dist = Math.hypot(cx - px, cy - py);
  const influence = Math.max(0, 1 - dist / 500);
  if (influence <= 0) return;
  body.vx += dx * 0.12 * influence;
  body.vy += dy * 0.12 * influence;
  body.jiggle = Math.min(1.5, body.jiggle + influence * 0.28);
  body.wetness = Math.min(1.25, body.wetness + influence * 0.06);
}

export function beginFingerGrab(
  body: FluidBody,
  pointerX: number,
  pointerY: number,
): void {
  const cx = body.x + body.width / 2;
  const cy = body.y + body.height / 2;
  body.grabOffset = { x: pointerX - cx, y: pointerY - cy };
  body.fingerTarget = { x: pointerX, y: pointerY };
  body.vx *= 0.2;
  body.vy *= 0.2;
  body.jiggle = Math.max(body.jiggle, 0.7);
  body.wetness = Math.min(1.35, body.wetness + 0.18);
}

export function updateFingerGrab(
  body: FluidBody,
  pointerX: number,
  pointerY: number,
): void {
  body.fingerTarget = { x: pointerX, y: pointerY };
}

export function releaseFingerGrab(body: FluidBody, samples: FluidSample[]): void {
  body.fingerTarget = null;
  const v = velocityFromSamples(samples);
  body.vx = v.vx * 1.1;
  body.vy = v.vy * 1.1;
  body.jiggle = Math.min(1.8, 0.55 + Math.hypot(v.vx, v.vy) * 0.06);
  body.settle = 0.9;
  body.wetness = Math.min(1.25, body.wetness + 0.1);
}

export function impulseSelect(body: FluidBody): void {
  body.jiggle = Math.min(1.5, body.jiggle + 0.55);
  body.settle = 0.5;
  body.vx += (Math.random() - 0.5) * 1.1;
  body.vy += (Math.random() - 0.5) * 1.1;
}

export function applyThrow(body: FluidBody, vx: number, vy: number): void {
  body.vx = vx;
  body.vy = vy;
  body.jiggle = Math.min(1.7, 0.45 + Math.hypot(vx, vy) * 0.055);
  body.settle = 0.75;
  body.fingerTarget = null;
}

/**
 * Size of a fresh ink spill from brush pressure (real liquid pool, not a dab).
 */
export function puddleSizeFromPressure(pressure: number): { width: number; height: number } {
  const p = clamp(pressure, 0.05, 1);
  const t = Math.pow(p, 0.7);
  // Generous pools — hard press floods a real puddle
  const base = 48 + t * 220;
  const aspect = 0.78 + p * 0.18 + (Math.random() - 0.5) * 0.12;
  return {
    width: base * (0.95 + Math.random() * 0.12),
    height: base * aspect,
  };
}

/**
 * Pour liquid ink at a brush tip into an existing puddle.
 * Grows volume, pulls mass toward the tip, stretches along the stroke.
 */
export function pourInk(
  body: FluidBody,
  tipX: number,
  tipY: number,
  pressure: number,
  brushVx: number,
  brushVy: number,
  deposit = 1,
): void {
  const p = clamp(pressure, 0.05, 1);
  const speed = Math.hypot(brushVx, brushVy);
  // Heavy deposit when pressing hard or moving slowly (soaking paper)
  const soak = 1 + (1 - Math.min(1, speed / 10)) * 0.85;
  const rate = (0.9 + p * 3.6) * deposit * soak;
  const addArea = rate * 72;
  body.mass = Math.min(MAX_PUDDLE * MAX_PUDDLE * 0.6, body.mass + addArea);

  const area = Math.max(1, body.width * body.height);
  const scale = Math.sqrt((area + addArea) / area);
  const cx = body.x + body.width / 2;
  const cy = body.y + body.height / 2;

  // Stretch along stroke (liquid trail / filament)
  const ang = speed > 0.12 ? Math.atan2(brushVy, brushVx) : 0;
  const alongX = Math.abs(Math.cos(ang));
  const alongY = Math.abs(Math.sin(ang));
  const trailBoost = 0.5 + Math.min(1.4, speed * 0.12);
  body.width = clamp(
    body.width * (1 + (scale - 1) * (0.5 + alongX * 0.95 * trailBoost)),
    22,
    MAX_PUDDLE,
  );
  body.height = clamp(
    body.height * (1 + (scale - 1) * (0.5 + alongY * 0.95 * trailBoost)),
    22,
    MAX_PUDDLE,
  );

  // When moving fast, elongate further along the stroke axis
  if (speed > 1.2) {
    const elong = 1 + Math.min(0.12, speed * 0.012) * p;
    body.width *= 1 + (elong - 1) * alongX;
    body.height *= 1 + (elong - 1) * alongY;
  }

  // Center of mass drifts strongly toward brush tip (pour point)
  const pull = 0.28 + p * 0.22 + Math.min(0.2, speed * 0.02);
  const ncx = cx + (tipX - cx) * pull;
  const ncy = cy + (tipY - cy) * pull;
  body.x = ncx - body.width / 2;
  body.y = ncy - body.height / 2;

  // Transfer brush motion into fluid (smear / spill inertia)
  body.vx = body.vx * 0.55 + brushVx * (0.65 + p * 0.4);
  body.vy = body.vy * 0.55 + brushVy * (0.65 + p * 0.4);
  body.jiggle = Math.min(2, 0.65 + p * 0.85 + speed * 0.05);
  body.wetness = Math.min(1.4, body.wetness + 0.05 + p * 0.08);
  body.settle = 0.65;

  // Keep brush attached so the puddle follows like wet ink
  body.fingerTarget = { x: tipX, y: tipY };
  body.grabOffset = {
    x: tipX - (body.x + body.width / 2),
    y: tipY - (body.y + body.height / 2),
  };
}

/**
 * Continuous stroke step: pour, and if tip is far, stretch a liquid filament
 * so the stroke stays one connected mass instead of discrete dabs.
 */
export function strokePour(
  body: FluidBody,
  tipX: number,
  tipY: number,
  pressure: number,
  brushVx: number,
  brushVy: number,
): void {
  const cx = body.x + body.width / 2;
  const cy = body.y + body.height / 2;
  const dist = Math.hypot(tipX - cx, tipY - cy);
  const reach = Math.max(body.width, body.height) * 0.55;

  // Extra deposit when covering new paper (gap between tip and mass)
  const gapBoost = dist > reach ? 1 + Math.min(2.2, (dist - reach) / 40) : 1;
  pourInk(body, tipX, tipY, pressure, brushVx, brushVy, gapBoost);

  // Filament stretch toward tip so the stroke looks continuous
  if (dist > reach * 0.4) {
    const ang = Math.atan2(tipY - cy, tipX - cx);
    const stretch = Math.min(dist * 0.55, 90) * (0.5 + pressure * 0.5);
    body.width = clamp(
      body.width + Math.abs(Math.cos(ang)) * stretch * 0.08,
      22,
      MAX_PUDDLE,
    );
    body.height = clamp(
      body.height + Math.abs(Math.sin(ang)) * stretch * 0.08,
      22,
      MAX_PUDDLE,
    );
    body.mass = Math.max(body.mass, body.width * body.height * 0.85);
  }
}

export function growPuddle(body: FluidBody, amount: number): void {
  const a = clamp(amount, 0, 16);
  body.width += a * 0.85;
  body.height += a * 0.75;
  body.mass = Math.max(body.mass, body.width * body.height);
  body.jiggle = Math.min(1.7, body.jiggle + 0.12);
  body.wetness = Math.min(1.3, body.wetness + 0.04);
}

/** Find nearest wet puddle within reach of brush tip for continuous liquid join */
export function findNearestPuddle(
  bodies: FluidBody[],
  tipX: number,
  tipY: number,
  maxDist = 120,
): FluidBody | null {
  let best: FluidBody | null = null;
  let bestD = maxDist;
  for (const b of bodies) {
    if (b.locked) continue;
    const cx = b.x + b.width / 2;
    const cy = b.y + b.height / 2;
    const reach = Math.max(b.width, b.height) * 0.62 + 56;
    const d = Math.hypot(cx - tipX, cy - tipY);
    if (d < reach && d < bestD) {
      bestD = d;
      best = b;
    }
  }
  return best;
}

/** Soft irregular liquid silhouette nodes for new pours */
export function liquidBrushNodes(pressure: number): BlobNode[] {
  const soft = 0.58 + pressure * 0.38;
  const irreg = 0.42 + pressure * 0.4;
  return generateBlobNodes(11 + Math.floor(pressure * 5), soft, irreg);
}

/** Re-liquify silhouette while pouring so edges stay organic */
export function refreshLiquidNodes(pressure: number, wetness: number): BlobNode[] {
  const soft = 0.5 + wetness * 0.35 + pressure * 0.15;
  const irreg = 0.35 + wetness * 0.3 + pressure * 0.2;
  return generateBlobNodes(10 + Math.floor(wetness * 4), soft, irreg);
}
